-- ============================================================================
-- 0007_group_d_import.sql
-- Group D legacy MySQL → Supabase migration
-- Source: group_D.sql  (group_id = 'D', admin_id = 4)
-- Extends: 0006_legacy_import.sql (Group A)
-- Idempotent: every INSERT uses ON CONFLICT DO NOTHING
-- Fixes applied: C1 C2 C3 C4 W1 W2 W3 W4
-- ============================================================================

-- ---------------------------------------------------------------------------
-- STEP 0 — EXTENSIONS
-- ---------------------------------------------------------------------------
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- ---------------------------------------------------------------------------
-- STEP 2 — HELPER FUNCTIONS  (defined early; dropped at end)
-- ---------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION _legacy_student_uuid(p_index text)
RETURNS uuid LANGUAGE sql IMMUTABLE AS $$
    SELECT md5('LEGACY_STUDENT::' || upper(trim(p_index)))::uuid;
$$;

CREATE OR REPLACE FUNCTION _legacy_session_uuid(p_id int)
RETURNS uuid LANGUAGE sql IMMUTABLE AS $$
    SELECT md5('LEGACY_SESSION::' || p_id::text)::uuid;
$$;

