JOIN attendance att
  ON att.session_id = _legacy_session_uuid(raw.session_id)
 AND att.student_id = _legacy_student_uuid(raw.student_index)
WHERE raw.session_id > 0
  AND EXISTS (SELECT 1 FROM class_sessions cs
              WHERE cs.id = _legacy_session_uuid(raw.session_id))
ON CONFLICT DO NOTHING;

-- 7b. Orphan dispute (session_id = 0) → audit_log
-- [W3 FIX] WHERE NOT EXISTS guard replaces the useless ON CONFLICT DO NOTHING
INSERT INTO audit_log (action, table_name, new_data, created_at)
SELECT
    'LEGACY_MIGRATION_ORPHANED_DISPUTE',
    'attendance_disputes',
    '{"legacy_id":1,"student_index":"BC/ITS/24/156","reason":"i scan but didnt go through","note":"session_id=0, no matching session. Group D migration."}'::jsonb,
    '2026-06-03 02:05:18'::timestamptz
WHERE NOT EXISTS (
    SELECT 1 FROM audit_log
    WHERE action = 'LEGACY_MIGRATION_ORPHANED_DISPUTE'
      AND new_data->>'legacy_id' = '1'
);

-- ---------------------------------------------------------------------------
-- STEP 8 — DROP HELPER FUNCTIONS
-- ---------------------------------------------------------------------------
DROP FUNCTION IF EXISTS _legacy_student_uuid(text);
DROP FUNCTION IF EXISTS _legacy_session_uuid(int);

-- ---------------------------------------------------------------------------
-- STEP 9 — VALIDATION BLOCK
-- ---------------------------------------------------------------------------
DO $$
DECLARE
    v_groups      int;
    v_students    int;
    v_memberships int;
    v_sessions    int;
    v_attendance  int;
    v_disputes    int;
BEGIN
    SELECT COUNT(*) INTO v_groups
        FROM groups WHERE group_name = 'D';
    SELECT COUNT(*) INTO v_students
        FROM students s
        JOIN group_memberships gm ON gm.student_id = s.id
        JOIN groups g ON g.id = gm.group_id
        WHERE g.group_name = 'D' AND gm.status = 'active';
    SELECT COUNT(*) INTO v_memberships
        FROM group_memberships gm
        JOIN groups g ON g.id = gm.group_id
        WHERE g.group_name = 'D';
    SELECT COUNT(*) INTO v_sessions FROM class_sessions;
    SELECT COUNT(*) INTO v_attendance FROM attendance;
    SELECT COUNT(*) INTO v_disputes FROM attendance_disputes;

    IF v_groups < 3 THEN
        RAISE EXCEPTION 'Group D migration failed: expected 3 Group D rows, got %.', v_groups;
    END IF;
    IF v_students < 100 THEN
        RAISE EXCEPTION 'Group D migration failed: expected ≥100 active Group D students, got %.', v_students;
    END IF;
    IF v_attendance < 2700 THEN
        RAISE EXCEPTION 'Group D migration failed: expected ≥2700 attendance rows, got %.', v_attendance;
    END IF;

    RAISE NOTICE '✓ Group D migration complete. groups=% students=% memberships=% sessions=% attendance=% disputes=%',
        v_groups, v_students, v_memberships, v_sessions, v_attendance, v_disputes;
END;
$$;
